import pandas as pdimport matplotlib.pyplot as pltimport osimport warningswarnings.filterwarnings('ignore')# ==========================================# 1. 解决 Matplotlib 中文显示问题# ==========================================# 根据你的操作系统，Matplotlib 需要指定中文字体，否则图表里的中文会变成方块import platformsystem = platform.system()if system == 'Windows':    plt.rcParams['font.sans-serif'] = ['SimHei']  # Windows 默认黑体elif system == 'Darwin':    plt.rcParams['font.sans-serif'] = ['Arial Unicode MS']  # macOS 字体else:    plt.rcParams['font.sans-serif'] = ['WenQuanYi Micro Hei']  # Linux 备用字体plt.rcParams['axes.unicode_minus'] = False  # 正常显示负号# ==========================================# 2. 绘图主函数# ==========================================def plot_matrices(input_dir="evaluation_results_matrix"):    if not os.path.exists(input_dir):        print(f"❌ 找不到文件夹 {input_dir}，请先运行实验生成数据！")        return    # 需要处理的 5 个指标    metrics = ["MSE", "RMSE", "RMSLE", "MAE", "MAPE"]    print(f"🎨 开始生成折线图...\n")    for metric in metrics:        # 读取之前生成的矩阵 CSV        file_path = os.path.join(input_dir, f"{metric}_Matrix_x10.csv")        if not os.path.exists(file_path):            print(f"⚠️ 找不到文件: {file_path}，已跳过。")            continue        # 读取数据：将第一列（错误率）设为 DataFrame 的索引 (Index)        df = pd.read_csv(file_path, index_col=0)        # 创建一个宽屏的图表对象        plt.figure(figsize=(12, 7))        # 使用 colormap 为 11 条线生成渐变好看的颜色        colors = plt.cm.viridis(np.linspace(0, 1, len(df.columns)))        # 遍历每一列（每一个清洗比例），画一条线        for i, col in enumerate(df.columns):            plt.plot(df.index, df[col],                     marker='o',  # 给每个数据点加上圆点标记                     linewidth=2,  # 线条粗细                     color=colors[i],  # 使用渐变色                     label=f'清洗比例 {col}')        # 设置图表标题和坐标轴标签        plt.title(f'{metric} 随错误率的变化趋势 (清洗比例对比)', fontsize=16, pad=15)        plt.xlabel('注入错误率', fontsize=14)        plt.ylabel(f'{metric} 值 ', fontsize=14)        # 设置图例：将图例放在图表右侧的外面，避免挡住曲线        '''plt.legend(title='图例 (清洗比例)',                   title_fontsize='12',                   bbox_to_anchor=(1.02, 1),                   loc='upper left',                   borderaxespad=0.)'''        # 增加虚线网格，方便对齐看数据        plt.grid(True, linestyle='--', alpha=0.6)        # 紧凑布局，防止坐标轴或图例被切掉        plt.tight_layout()        # 生成图片文件名并保存        output_png = os.path.join(input_dir, f"{metric}_Trend_Chart.png")        plt.savefig(output_png, dpi=300)  # dpi=300 保证图片超高清        plt.close()  # 关闭当前画布，防止内存泄露        print(f"  ✅ 生成图片: {output_png}")    print("\n🎉 所有折线图绘制完成！请前往文件夹查看。")if __name__ == "__main__":    # 需要先引入 numpy 给 colormap 算渐变色用    import numpy as np    plot_matrices()